import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Careers = () => {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true); // Loading state add ki
  const [selectedJob, setSelectedJob] = useState(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [formData, setFormData] = useState({ name: '', email: '', resume: null });

  // 1. Backend se Jobs fetch karna (Port 5001)
  useEffect(() => {
    const fetchJobs = async () => {
      try {
        const res = await axios.get('http://localhost:5001/api/jobs');
        setJobs(res.data);
        setLoading(false);
      } catch (err) {
        console.error("Backend connection failed", err);
        setLoading(false);
      }
    };
    fetchJobs();
  }, []);

  // 2. Application Submit handle karna
  const handleApply = async (e) => {
    e.preventDefault();
    if(!formData.resume) return alert("Please upload a resume");

    const data = new FormData();
    data.append('name', formData.name);
    data.append('email', formData.email);
    data.append('jobId', selectedJob.title); // Title ya ID bhej sakte hain
    data.append('resume', formData.resume);

    try {
      await axios.post('http://localhost:5001/api/apply', data);
      alert("Application Sent Successfully!");
      setIsFormOpen(false);
    } catch (err) {
      console.error(err);
      alert("Error sending application. Make sure server is running on 5001");
    }
  };

  return (
    <div className="bg-white font-sans">
      {/* ... (Aapka Header Section same rahega) ... */}

      {/* JOBS BOARD */}
      <section className="py-24 px-6 max-w-7xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-end justify-between mb-16 gap-8">
          <div>
            <h2 className="text-5xl font-black text-gray-950 tracking-tighter">Open Positions</h2>
          </div>
        </div>

        <div className="grid gap-6">
          {loading ? (
            <p className="text-center font-bold text-gray-400 text-xl">Loading jobs from Atlas...</p>
          ) : jobs.length > 0 ? (
            jobs.map((job) => (
              <div key={job._id} className="group flex flex-col md:flex-row md:items-center justify-between p-10 bg-white border border-gray-100 rounded-[2.5rem] hover:shadow-2xl transition-all">
                <div className="flex-1">
                  <span className="inline-block px-3 py-1 bg-orange-50 text-orange-600 rounded-full text-[10px] font-black uppercase tracking-widest mb-4">
                    {job.type || 'On-site'}
                  </span>
                  <h3 className="text-3xl font-black text-gray-950 mb-2">{job.title}</h3>
                  <p className="text-gray-500 font-bold uppercase text-[14px] tracking-widest">
                    {job.loc} • {job.salary}
                  </p>
                </div>
                <div className="mt-8 md:mt-0">
                  <button 
                    onClick={() => { setSelectedJob(job); setIsFormOpen(true); }}
                    className="bg-gray-950 text-white px-12 py-4 rounded-2xl font-black hover:bg-orange-600 transition-all"
                  >
                    Apply Now
                  </button>
                </div>
              </div>
            ))
          ) : (
            <p className="text-center text-gray-500">No jobs found in Database.</p>
          )}
        </div>
      </section>

      {/* ... (Aapka Modal Section same rahega) ... */}
    </div>
  );
};

export default Careers;
